16	)
17	
18	const (
19		// addIndexFieldTimeout is the timeout used for adding an Index Field to a cache.
20		addIndexFieldTimeout = 2 * time.Minute
21	)
22	
23	type config struct {
24		namespacedNameFilter NamespacedNameFilterFunc
25		k8sPredicate         predicate.Predicate
26		fieldIndices         index.FieldIndices
27		newReconciler        NewReconcilerFunc
28		onlyMetadata         bool
29	}
30	
31	// NewReconcilerFunc defines a function that creates a new Reconciler. Used for unit-testing.
32	type NewReconcilerFunc func(cfg ReconcilerConfig) *Reconciler
33	
34	// Option defines configuration options for registering a controller.
35	type Option func(*config)
36	
37	// WithNamespacedNameFilter enables filtering of objects by NamespacedName by the controller.
38	func WithNamespacedNameFilter(filter NamespacedNameFilterFunc) Option {
39		return func(cfg *config) {
40			cfg.namespacedNameFilter = filter
41		}
42	}
43	
44	// WithK8sPredicate enables filtering of events before they are sent to the controller.
45	func WithK8sPredicate(p predicate.Predicate) Option {
46		return func(cfg *config) {
47			cfg.k8sPredicate = p
48		}
49	}
50	
51	// WithFieldIndices adds indices to the FieldIndexer of the manager.
52	func WithFieldIndices(fieldIndices index.FieldIndices) Option {
53		return func(cfg *config) {
54			cfg.fieldIndices = fieldIndices
55		}
56	}
57	
58	// WithNewReconciler allows us to mock reconciler creation in the unit tests.
59	func WithNewReconciler(newReconciler NewReconcilerFunc) Option {
60		return func(cfg *config) {
61			cfg.newReconciler = newReconciler
62		}
63	}
64	
65	// WithOnlyMetadata tells the controller to only cache metadata, and to watch the API server in metadata-only form.
66	// If using this option, you must set the GroupVersionKind on the ObjectType you pass into the Register function.
67	// If watching a resource with OnlyMetadata, for example the v1.Pod, you must not Get and List using the v1.Pod type.
68	// Instead, you must use the special metav1.PartialObjectMetadata type.
69	func WithOnlyMetadata() Option {
70		return func(cfg *config) {
71			cfg.onlyMetadata = true
72		}
73	}
74	
75	func defaultConfig() config {
76		return config{
77			newReconciler: NewReconciler,
78		}
79	}
80	
81	// Register registers a new controller for the object type in the manager and configure it with the provided options.
82	// If the options include WithFieldIndices, it will add the specified indices to FieldIndexer of the manager.
83	// The registered controller will send events to the provided channel.
84	func Register(
85		ctx context.Context,
86		objectType ngftypes.ObjectType,
87		name string,
88		mgr manager.Manager,
89		eventCh chan<- any,
90		options ...Option,
91	) error {
92		cfg := defaultConfig()
93	
94		for _, opt := range options {
95			opt(&cfg)
96		}
97	
98		for field, indexerFunc := range cfg.fieldIndices {
99			if err := AddIndex(
100				ctx,
101				mgr.GetFieldIndexer(),
102				objectType,
103				field,
104				indexerFunc,
105			); err != nil {
106				return err
107			}
108		}
109	
110		var forOpts []ctlrBuilder.ForOption
111		if cfg.onlyMetadata {
112			if objectType.GetObjectKind().GroupVersionKind().Empty() {
113				panic("the object must have its GVK set")
114			}
115			forOpts = append(forOpts, ctlrBuilder.OnlyMetadata)
116		}
117	
118		builder := ctlr.NewControllerManagedBy(mgr).Named(name).For(objectType, forOpts...)
119	
120		if cfg.k8sPredicate != nil {
121			builder = builder.WithEventFilter(cfg.k8sPredicate)
122		}
123	
124		recCfg := ReconcilerConfig{
125			Getter:               mgr.GetClient(),
126			ObjectType:           objectType,
127			EventCh:              eventCh,
128			NamespacedNameFilter: cfg.namespacedNameFilter,
129			OnlyMetadata:         cfg.onlyMetadata,
130		}
131	
132		if err := builder.Complete(cfg.newReconciler(recCfg)); err != nil {
133			return fmt.Errorf("cannot build a controller for %T: %w", objectType, err)
134		}
135	
136		return nil
137	}
138	
139	func AddIndex(
140		ctx context.Context,
141		indexer client.FieldIndexer,
142		objectType ngftypes.ObjectType,
143		field string,
144		indexerFunc client.IndexerFunc,
145	) error {
146		c, cancel := context.WithTimeout(ctx, addIndexFieldTimeout)
147		defer cancel()
148	
149		if err := indexer.IndexField(c, objectType, field, indexerFunc); err != nil {
150			return fmt.Errorf("failed to add index for %T for field %s: %w", objectType, field, err)
151		}
152	
153		return nil
154	}
