18	// Diff prints the diff between two structs.
19	// It is useful in testing to compare two structs when they are large. In such a case, without Diff it will be difficult
20	// to pinpoint the difference between the two structs.
21	func Diff(want, got any) string {
22		r := cmp.Diff(want, got)
23	
24		if r != "" {
25			return "(-want +got)\n" + r
26		}
27		return r
28	}
29	
30	// GetPointer takes a value of any type and returns a pointer to it.
31	func GetPointer[T any](v T) *T {
32		return &v
33	}
34	
35	// PrepareTimeForFakeClient processes the time similarly to the fake client
36	// from sigs.k8s.io/controller-runtime/pkg/client/fake
37	// making it is possible to use it in tests when comparing against values returned by the fake client.
38	// It panics if it fails to process the time.
39	func PrepareTimeForFakeClient(t metav1.Time) metav1.Time {
40		b, err := t.Marshal()
41		if err != nil {
42			panic(fmt.Errorf("failed to marshal time: %w", err))
43		}
44	
45		if err = t.Unmarshal(b); err != nil {
46			panic(fmt.Errorf("failed to unmarshal time: %w", err))
47		}
48	
49		return t
50	}
51	
52	// MustCastObject casts the client.Object to the specified type that implements it.
53	func MustCastObject[T client.Object](object client.Object) T {
54		if obj, ok := object.(T); ok {
55			return obj
56		}
57	
58		panic(fmt.Errorf("unexpected object type %T", object))
59	}
60	
61	// EqualPointers returns whether two pointers are equal.
62	// Pointers are considered equal if one of the following is true:
63	// - They are both nil.
64	// - One is nil and the other is empty (e.g. nil string and "").
65	// - They are both non-nil, and their values are the same.
66	func EqualPointers[T comparable](p1, p2 *T) bool {
67		if p1 == nil && p2 == nil {
68			return true
69		}
70	
71		var p1Val, p2Val T
72	
73		if p1 != nil {
74			p1Val = *p1
75		}
76	
77		if p2 != nil {
78			p2Val = *p2
79		}
80	
81		return p1Val == p2Val
82	}
83	
84	// MustExecuteTemplate executes the template with the given data.
85	func MustExecuteTemplate(templ *template.Template, data any) []byte {
86		var buf bytes.Buffer
87	
88		if err := templ.Execute(&buf, data); err != nil {
89			panic(err)
90		}
91	
92		return buf.Bytes()
93	}
94	
95	// CapitalizeString capitalizes the first letter of the string.
96	func CapitalizeString(s string) string {
97		if s == "" {
98			return s
99		}
100	
101		return strings.ToUpper(s[:1]) + s[1:]
102	}
103	
104	// URLHash returns the first 16 hex characters of the SHA-256 digest of rawURL.
105	// Used to derive a stable, filesystem-safe component for keys.
106	func URLHash(rawURL string) string {
107		sum := sha256.Sum256([]byte(rawURL))
108		return hex.EncodeToString(sum[:])[:16]
109	}
110	
111	// ToSafeFileName converts any string to a filesystem-safe filename using SHA256 hash.
112	func ToSafeFileName(input string) string {
113		hasher := sha256.New()
114		hasher.Write([]byte(input))
115		return base64.URLEncoding.EncodeToString(hasher.Sum(nil))
116	}
