9	// GatewayClassPredicate implements a predicate function based on the controllerName of a GatewayClass.
10	// This predicate will skip events for GatewayClasses that don't reference this controller.
11	type GatewayClassPredicate struct {
12		predicate.Funcs
13		ControllerName string
14	}
15	
16	// Create implements default CreateEvent filter for validating a GatewayClass controllerName.
17	func (gcp GatewayClassPredicate) Create(e event.CreateEvent) bool {
18		if e.Object == nil {
19			return false
20		}
21	
22		gc, ok := e.Object.(*v1.GatewayClass)
23		if !ok {
24			return false
25		}
26	
27		return string(gc.Spec.ControllerName) == gcp.ControllerName
28	}
29	
30	// Update implements default UpdateEvent filter for validating a GatewayClass controllerName.
31	func (gcp GatewayClassPredicate) Update(e event.UpdateEvent) bool {
32		if e.ObjectOld != nil {
33			gcOld, ok := e.ObjectOld.(*v1.GatewayClass)
34			if ok && string(gcOld.Spec.ControllerName) == gcp.ControllerName {
35				return true
36			}
37		}
38	
39		if e.ObjectNew != nil {
40			gcNew, ok := e.ObjectNew.(*v1.GatewayClass)
41			if ok && string(gcNew.Spec.ControllerName) == gcp.ControllerName {
42				return true
43			}
44		}
45	
46		return false
47	}
48	
49	// Delete implements default DeleteEvent filter for validating a GatewayClass controllerName.
50	func (gcp GatewayClassPredicate) Delete(e event.DeleteEvent) bool {
51		if e.Object == nil {
52			return false
53		}
54	
55		gc, ok := e.Object.(*v1.GatewayClass)
56		if !ok {
57			return false
58		}
59	
60		return string(gc.Spec.ControllerName) == gcp.ControllerName
61	}
