11	// SecretNamePredicate implements a predicate function that returns true if the Secret matches the expected
12	// namespace and one of the expected names.
13	type SecretNamePredicate struct {
14		predicate.Funcs
15		Namespace   string
16		SecretNames []string
17	}
18	
19	// Create filters CreateEvents based on the Secret name.
20	func (sp SecretNamePredicate) Create(e event.CreateEvent) bool {
21		if e.Object == nil {
22			return false
23		}
24	
25		if secret, ok := e.Object.(*corev1.Secret); ok {
26			return secretMatches(secret, sp.Namespace, sp.SecretNames)
27		}
28	
29		return false
30	}
31	
32	// Update filters UpdateEvents based on the Secret name.
33	func (sp SecretNamePredicate) Update(e event.UpdateEvent) bool {
34		if e.ObjectNew == nil {
35			return false
36		}
37	
38		if secret, ok := e.ObjectNew.(*corev1.Secret); ok {
39			return secretMatches(secret, sp.Namespace, sp.SecretNames)
40		}
41	
42		return false
43	}
44	
45	// Delete filters DeleteEvents based on the Secret name.
46	func (sp SecretNamePredicate) Delete(e event.DeleteEvent) bool {
47		if e.Object == nil {
48			return false
49		}
50	
51		if secret, ok := e.Object.(*corev1.Secret); ok {
52			return secretMatches(secret, sp.Namespace, sp.SecretNames)
53		}
54	
55		return false
56	}
57	
58	// Generic filters GenericEvents based on the Secret name.
59	func (sp SecretNamePredicate) Generic(e event.GenericEvent) bool {
60		if e.Object == nil {
61			return false
62		}
63	
64		if secret, ok := e.Object.(*corev1.Secret); ok {
65			return secretMatches(secret, sp.Namespace, sp.SecretNames)
66		}
67	
68		return false
69	}
70	
71	func secretMatches(secret *corev1.Secret, namespace string, names []string) bool {
72		if secret.GetNamespace() != namespace {
73			return false
74		}
75	
76		return slices.Contains(names, secret.GetName())
77	}
