10	const (
11		// KubernetesServiceNameIndexField is the name of the Index Field used to index EndpointSlices by their service
12		// owners.
13		KubernetesServiceNameIndexField = "k8sServiceName"
14		// KubernetesServiceNameLabel is the label used to identify the Kubernetes service name on an EndpointSlice.
15		KubernetesServiceNameLabel = "kubernetes.io/service-name"
16	)
17	
18	// CreateEndpointSliceFieldIndices creates a FieldIndices map for the EndpointSlice resource.
19	func CreateEndpointSliceFieldIndices() FieldIndices {
20		return FieldIndices{
21			KubernetesServiceNameIndexField: ServiceNameIndexFunc,
22		}
23	}
24	
25	// ServiceNameIndexFunc is a client.IndexerFunc that parses a Kubernetes object and returns the value of the
26	// Kubernetes service-name label.
27	// Used to index EndpointSlices by their service owners.
28	func ServiceNameIndexFunc(obj client.Object) []string {
29		slice, ok := obj.(*discoveryV1.EndpointSlice)
30		if !ok {
31			panic(fmt.Sprintf("expected an EndpointSlice; got %T", obj))
32		}
33	
34		name := GetServiceNameFromEndpointSlice(slice)
35		if name == "" {
36			return nil
37		}
38	
39		return []string{name}
40	}
41	
42	// GetServiceNameFromEndpointSlice returns the value of the Kubernetes service-name label from an EndpointSlice.
43	func GetServiceNameFromEndpointSlice(slice *discoveryV1.EndpointSlice) string {
44		if slice.Labels == nil {
45			return ""
46		}
47	
48		return slice.Labels[KubernetesServiceNameLabel]
49	}
